const envelope = $json.body && typeof $json.body === 'object' ? $json.body : $json;
const event = envelope.event;
const payload = envelope.payload || {};
if (event !== 'message' || payload.fromMe === true) return [];

const chatId = String(payload.from || payload.chatId || payload.key?.remoteJid || '').trim();
if (!chatId || /@g\.us$/i.test(chatId)) return [];

const mediaUrl = String(payload.media?.url || '').trim();
const mediaMimeType = String(payload.media?.mimetype || '').trim();
const hasImage = Boolean(payload.hasMedia && mediaUrl && /^image\//i.test(mediaMimeType));
const messageText = [
  payload.body,
  payload.text?.body,
  payload.message?.conversation,
  payload.message?.extendedTextMessage?.text,
  payload.message?.imageMessage?.caption,
  payload.message?.videoMessage?.caption
].find((value) => typeof value === 'string' && value.trim()) || '';
if (!messageText && !hasImage) return [];

const senderId = String(payload.remoteJidAlt || payload._data?.remoteJidAlt || payload._data?.id?.remoteJidAlt || payload.author || payload.participant || payload.key?.participant || chatId).trim();
const phone = senderId.replace(/@s\.whatsapp\.net$/i, '').replace(/@c\.us$/i, '').replace(/@lid$/i, '');
const normalizedText = String(messageText || '').trim();

return [{ json: {
  session: envelope.session || $json.session || 'default',
  event,
  phone,
  chatId,
  senderId,
  text: normalizedText,
  logText: normalizedText || (hasImage ? '[imagem recebida]' : ''),
  hasMedia: Boolean(payload.hasMedia),
  hasImage,
  mediaUrl,
  mediaMimeType,
  rawPayload: payload,
  rawEnvelope: envelope
}}];

const apiBase = 'http://api:3000/Liftflex_API/rest/v2';
async function requestJson(url, options = {}) {
  const response = await fetch(url, { ...options, headers: { ...(options.body ? { 'Content-Type': 'application/json' } : {}), ...(options.headers || {}) } });
  const text = await response.text();
  let payload = {};
  if (text) {
    try { payload = JSON.parse(text); } catch (_error) { payload = { raw: text }; }
  }
  if (!response.ok) return { Success: false, success: false, statusCode: response.status, error: payload };
  return payload;
}

const ctx = { ...$json };
if (ctx.hasImage && ctx.mediaUrl && !ctx.document) {
  const extraction = await requestJson(apiBase + '/ExtractDocumentFromWhatsAppImage', {
    method: 'POST',
    body: JSON.stringify({ MediaUrl: ctx.mediaUrl, MimeType: ctx.mediaMimeType, Caption: ctx.text || '' })
  });
  ctx.document = extraction.document || extraction.Document || '';
  ctx.documentSource = extraction.documentSource || (ctx.document ? 'image' : 'image_not_found');
  ctx.imageExtractionFound = Boolean(ctx.document);
  ctx.imageExtractionReason = extraction.imageExtractionReason || extraction.Reason || '';
}
return [{ json: ctx }];

function normalizeText(value) {
  return String(value || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/\s+/g, ' ').trim();
}
function isOptOut(text) {
  return new Set(['parar', 'stop', 'descadastrar', 'cancelar cobranca', 'remover meu numero', 'nao enviar', 'nao mande']).has(normalizeText(text));
}
function shouldShowWelcome(ctx) {
  const normalized = normalizeText(ctx.text);
  const directKeywords = ['boleto', '2 via', 'segunda via', 'reenviar', 'reenvio', 'linha digitavel', 'humano', 'atendente', 'operador', 'suporte'];
  const greetings = ['oi', 'ola', 'bom dia', 'boa tarde', 'boa noite', 'preciso de ajuda', 'quero ajuda', 'quero atendimento'];
  const hasDirectIntent = Boolean(ctx.hasImage || ctx.document || directKeywords.some((keyword) => normalized.includes(keyword)));
  return (ctx.conversationState === 'idle' || !ctx.conversationStateFound) && !hasDirectIntent && greetings.some((keyword) => normalized === keyword || normalized.includes(keyword));
}
function resolveIntent(ctx) {
  const normalized = normalizeText(ctx.text);
  const rawText = String(ctx.text || '').trim();
  const state = ctx.conversationState || 'idle';
  const activeFlow = ctx.conversationFlow === 'segunda_via_boleto' ? 'segunda_via_boleto' : '';
  const tokenCount = normalized ? normalized.split(' ').filter(Boolean).length : 0;
  const menuOption = normalized.match(/^(1|2)$/)?.[1] || '';
  const documentOnlyMessage = Boolean(ctx.document && /^[\d\s.\-/]+$/.test(rawText) && rawText.length <= 22);
  const mentionsSecondVia = ['boleto', '2 via', 'segunda via', 'reenviar', 'reenvio', 'linha digitavel'].some((keyword) => normalized.includes(keyword));
  const requestsHuman = ['humano', 'atendente', 'operador', 'pessoa', 'suporte'].some((keyword) => normalized.includes(keyword));
  const looksLikeKnowledgeQuery = ['qual', 'quais', 'onde', 'como', 'quando', 'endereco', 'telefone', 'numero', 'email', 'e-mail', 'horario', 'empresa', 'nippon', '?'].some((keyword) => rawText.toLowerCase().includes(keyword) || normalized.includes(keyword)) || tokenCount >= 4;

  if (!ctx.document && ctx.hasImage && ctx.mediaUrl) return { route: 'ask_document', intent: 'ask_document', nextFlow: 'segunda_via_boleto', reason: 'image_document_not_found' };

  if (state === 'awaiting_menu_selection') {
    if (menuOption === '1') return { route: 'ask_document', intent: 'ask_document', nextFlow: 'segunda_via_boleto', reason: 'menu_option_second_via' };
    if (menuOption === '2') return { route: 'ask_knowledge', intent: 'ask_knowledge', nextFlow: 'knowledge_base', reason: 'menu_option_other_subject' };
    if (requestsHuman) return { route: 'knowledge', intent: 'default_operator', nextFlow: '', reason: 'menu_operator' };
    if (mentionsSecondVia || ctx.hasImage || documentOnlyMessage) return { route: ctx.document ? 'boleto' : 'ask_document', intent: ctx.document ? 'segunda_via_boleto' : 'ask_document', nextFlow: 'segunda_via_boleto', reason: ctx.document ? 'menu_second_via_with_document' : 'menu_second_via_without_document' };
    if (!looksLikeKnowledgeQuery) return { route: 'welcome', intent: 'show_welcome_menu', nextFlow: '', reason: 'menu_repeat' };
  }

  if (state === 'awaiting_knowledge_question' && normalized) return { route: 'knowledge', intent: 'knowledge_base_question', nextFlow: '', reason: 'state_awaiting_knowledge_question' };
  if (requestsHuman || looksLikeKnowledgeQuery) return { route: 'knowledge', intent: requestsHuman ? 'default_operator' : 'knowledge_base_question', nextFlow: '', reason: requestsHuman ? 'handoff_keyword' : 'knowledge_query' };
  if (documentOnlyMessage) return { route: 'boleto', intent: 'segunda_via_boleto', nextFlow: activeFlow || 'segunda_via_boleto', reason: 'document_only_message' };
  if (ctx.document && (mentionsSecondVia || state === 'awaiting_document' || activeFlow === 'segunda_via_boleto' || ctx.documentSource)) return { route: 'boleto', intent: 'segunda_via_boleto', nextFlow: 'segunda_via_boleto', reason: 'document_with_receivables_context' };
  if (!ctx.document && (mentionsSecondVia || state === 'awaiting_document' || activeFlow === 'segunda_via_boleto')) return { route: 'ask_document', intent: 'ask_document', nextFlow: 'segunda_via_boleto', reason: 'boleto_keyword_without_document' };
  return { route: 'knowledge', intent: 'default_operator', nextFlow: '', reason: 'default_operator' };
}
let decision;
if (isOptOut($json.text)) decision = { route: 'opt_out', intent: 'opt_out', nextFlow: '', reason: 'opt_out_command' };
else if (shouldShowWelcome($json)) decision = { route: 'welcome', intent: 'welcome_menu', nextFlow: '', reason: 'welcome_menu' };
else decision = resolveIntent($json);
return [{ json: { ...$json, ...decision, resolvedFlow: decision.nextFlow || ($json.conversationFlow === 'segunda_via_boleto' ? 'segunda_via_boleto' : ''), classificationReason: decision.reason } }];

const apiBase = 'http://api:3000/Liftflex_API/rest/v2';
async function post(path, body) {
  await fetch(apiBase + path, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) });
}
await post('/SetWhatsAppOptOut', { Telefone: $json.phone, OptOut: true, Reason: 'Cliente solicitou bloqueio de cobrancas automaticas no WhatsApp', Source: 'chatbot', SourceMessage: $json.text });
await post('/ClearConversationState', { Telefone: $json.phone });
return [{ json: { ...$json, replyText: 'Entendido. Nao enviaremos novas cobrancas automaticas por este WhatsApp. Se quiser retomar no futuro, fale com um operador.', logIntent: 'opt_out' } }];

const replyText = '👔 Olá. Bem-vindo ao canal de atendimento da Nippon Elevadores.

Através deste menu, podemos auxiliá-lo com questões de Contas a Receber. Por gentileza, selecione a opção que melhor atende à sua necessidade no momento:

🔸 1. Segunda via de boleto
🔸 2. Outros assuntos

Caso a sua solicitação demande suporte adicional, um atendente dará continuidade ao seu atendimento.';
return [{ json: { ...$json, replyText, logIntent: 'welcome_menu' } }];

const replyText = $json.classificationReason === 'image_document_not_found'
  ? 'Nao consegui identificar o CPF ou CNPJ na imagem. Se preferir, envie o documento digitado ou uma foto mais legivel do boleto.'
  : 'Para localizar seu boleto, por favor informe o CPF ou CNPJ vinculado ao cadastro. Se preferir, envie uma foto legivel do boleto.';
return [{ json: { ...$json, resolvedFlow: 'segunda_via_boleto', nextFlow: 'segunda_via_boleto', replyText, logIntent: 'ask_document' } }];

const incoming = $item(0).$node["Normalize WhatsApp Message"].json;
const config = $item(0).$node["Get MVP Config"].json;
const state = $json || {};
const digits = String(incoming.text || '').replace(/\D/g, '');
const documentMatch = digits.match(/(\d{14}|\d{11})/);
return [
  {
    json: {
      ...incoming,
      document: documentMatch ? documentMatch[1] : '',
      fallbackMessage: config.DefaultFallbackMessage || 'Recebemos sua mensagem e em breve um operador do contas a receber dara continuidade ao atendimento.',
      defaultDelayDays: Number(config.DefaultDelayDays || 3),
      initialMessage: config.InitialWhatsAppMessage,
      conversationState: state.CurrentState || 'idle',
      conversationFlow: state.ActiveFlow || '',
      conversationLastIntent: state.LastIntent || '',
      conversationContext: state.Context || {},
      conversationStateFound: Boolean(state.Found),
      conversationStateExpiresAt: state.ExpiresAt || null,
      conversationStateTtlHours: Number(config.ConversationStateTtlHours || 12)
    }
  }
];

const context = $item(0).$node["Merge Chat Context"].json;
const boletos = $json.Boletos || [];
const boleto = boletos[0];
if (!boleto) {
  return [{ json: { ...context, canUpdate: false, replyText: 'Nao localizamos um boleto para reenvio neste momento. Em breve um operador dara continuidade ao atendimento.', logIntent: 'segunda_via_boleto' } }];
}
return [{ json: { ...context, resolvedFlow: 'segunda_via_boleto', canUpdate: true, boletoId: boleto.Identificador, tenantId: 1, currentDueDate: boleto.Vencimento, linhaDigitavel: boleto.LinhaDigitavel, logIntent: 'segunda_via_boleto' } }];

const context = $item(0).$node["Prepare Boleto Reply"].json;
const closingText = 'Agradecemos o seu contato com a Nippon Elevadores. Este atendimento foi encerrado. Se precisar, estamos a disposicao.';
const replyText = 'Localizamos seu boleto. Linha digitavel: ' + context.linhaDigitavel + '\n\n' + closingText;
return [{ json: { ...context, replyText, logIntent: 'segunda_via_boleto' } }];

const context = $item(0).$node["Merge Chat Context"].json;
const answer = $json.knowledgeBaseAnswer || $json.Answer || '';
return [{ json: { ...context, replyText: answer, logIntent: 'knowledge_base_answer', classificationReason: 'knowledge_base_answer' } }];

const context = $item(0).$node["Merge Chat Context"].json;
const fallbackMessage = context.fallbackMessage || 'Nao encontrei essa informacao na base de conhecimento agora. Vou encaminhar seu atendimento para um operador.';
return [{ json: { ...context, replyText: fallbackMessage, logIntent: 'default_operator' } }];
